<?= $this->extend('layouts/panel') ?><?= $this->section('content') ?><div class="page-actions"><div><p class="page-lead">Tedarik siparişlerini ve mal kabul durumunu izleyin.</p></div><div class="action-group"><a class="button button--secondary" href="<?= site_url('panel/tedarikciler') ?>">Tedarikçiler</a><?php if($canCreate): ?><a class="button" href="<?= site_url('panel/alislar/yeni') ?>">Yeni alış</a><?php endif; ?></div></div><section class="panel-card"><div class="table-wrap"><table class="data-table"><thead><tr><th>Belge</th><th>Tedarikçi</th><th>Depo</th><th>Tarih</th><?php if($canViewCost): ?><th>Toplam</th><?php endif; ?><th>Durum</th><th></th></tr></thead><tbody><?php $labels=['ordered'=>'Sipariş verildi','partial'=>'Kısmi kabul','received'=>'Tamamlandı','cancelled'=>'İptal'];foreach($orders as $order): ?><tr><td data-label="Belge"><strong><?= esc($order['order_number']) ?></strong></td><td data-label="Tedarikçi"><?= esc($order['company_name']) ?></td><td data-label="Depo"><?= esc($order['warehouse_name']) ?></td><td data-label="Tarih"><?= esc(date('d.m.Y',strtotime($order['order_date']))) ?></td><?php if($canViewCost): ?><td data-label="Toplam"><?= number_format((float)$order['subtotal'],2,',','.') ?> ₺</td><?php endif; ?><td data-label="Durum"><span class="badge <?= $order['status']==='received'?'badge--success':'badge--warning' ?>"><?= esc($labels[$order['status']]??$order['status']) ?></span></td><td data-label="İşlem"><a class="text-link" href="<?= site_url('panel/alislar/'.$order['id']) ?>">Aç</a></td></tr><?php endforeach; ?></tbody></table></div><?php if($orders===[]): ?><div class="empty-state"><span>A</span><h2>Alış siparişi yok</h2></div><?php endif; ?></section><?= $this->endSection() ?>
